def snakesAndLadders(board):
    n = len(board)
    cells = [None] * (n*n + 1)
    label = 1; columns = list(range(n))
    for row in range(n-1, -1, -1):
        for column in columns:
            cells[label] = board[row][column]
            label += 1
        columns.reverse()
    dist = {1: 0}; q = collections.deque([1])
    while q:
        curr = q.popleft()
        if curr == n*n: return dist[curr]
        for next_sq in range(curr + 1, min(curr + 6, n*n) + 1):
            dest = cells[next_sq] if cells[next_sq] != -1 else next_sq
            if dest not in dist: dist[dest] = dist[curr] + 1; q.append(dest)
    return -1

